// Expand around center — O(n^2) time, O(1) space
function longestPalindrome(s) {
  let start = 0, maxLen = 0;

  function expand(l, r) {
    while (l >= 0 && r < s.length && s[l] === s[r]) {
      if (r - l + 1 > maxLen) {
        maxLen = r - l + 1;
        start = l;
      }
      l--; r++;
    }
  }

  for (let i = 0; i < s.length; i++) {
    expand(i, i);     // odd-length
    expand(i, i + 1); // even-length
  }

  return s.slice(start, start + maxLen);
}

// O(n) Manacher's algorithm exists but expand-around-center suffices for interviews.
longestPalindrome("babad");  // "bab"
longestPalindrome("cbbd");   // "bb"
longestPalindrome("racecar"); // "racecar"

// Method 1: Set (preserves insertion order in JS)
function removeDuplicates(str) {
  return [...new Set(str)].join('');
}

// Method 2: Manual tracking
function removeDuplicates2(str) {
  const seen = new Set();
  let result = '';
  for (const c of str) {
    if (!seen.has(c)) {
      seen.add(c);
      result += c;
    }
  }
  return result;
}

removeDuplicates("programming"); // "progamin"
removeDuplicates("hello world"); // "helo wrd"

// Sort each word as key — O(n * k log k) where k = max word length
function groupAnagrams(strs) {
  const map = new Map();

  for (const str of strs) {
    const key = str.split('').sort().join('');
    if (!map.has(key)) map.set(key, []);
    map.get(key).push(str);
  }

  return [...map.values()];
}

// Alternative: Count-based key (O(n*k), no sorting)
function groupAnagrams2(strs) {
  const map = new Map();
  for (const str of strs) {
    const count = new Array(26).fill(0);
    for (const c of str) count[c.charCodeAt(0) - 97]++;
    const key = count.join(',');
    if (!map.has(key)) map.set(key, []);
    map.get(key).push(str);
  }
  return [...map.values()];
}

groupAnagrams(["eat","tea","tan","ate","nat","bat"]);
// [["eat","tea","ate"],["tan","nat"],["bat"]]

