string Compress(string s) {
  if (string.IsNullOrEmpty(s)) return s;

  var sb = new StringBuilder();
  int count = 1;

  for (int i = 1; i <= s.Length; i++) {
    if (i < s.Length && s[i] == s[i - 1]) {
      count++;
    } else {
      sb.Append(s[i - 1]);
      sb.Append(count);
      count = 1;
    }
  }

  string result = sb.ToString();
  return result.Length < s.Length ? result : s;
}

